#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int maxSubArray(vector<int>& nums) {
        if (nums.empty()) {
            return 0;
        }
        int max_sum = INT_MIN;
        int current_sum = 0;
        for (int num : nums) {
            current_sum = max(num, current_sum + num);
            max_sum = max(max_sum, current_sum);
        }
        return max_sum;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) cin >> nums[i];
    Solution sol;
    int ans = sol.maxSubArray(nums);
    cout << ans << "\n";
    return 0;
}
